revision.text:
/* {{pp-template}} */
.file-information {
	width: 100%;
	padding: 5px;
	border: 1px solid #a2a9b1;
	background-color: var( --background-color-interactive-subtle, #f8f9fa );
	font-size: 95%;
	box-sizing: border-box;
}

.file-information caption {
	font-weight: bold;
}

.file-information td {
	padding: 2px;
	vertical-align: top;
}

.file-information th {
	padding: 2px;
	vertical-align: top;
	background: #ccf;
    color: black;
	text-align: right;
	padding-right: 0.4em;
}

/* higher specificity than the likely-later .imbox styles */
.file-information td .imbox {
	margin: 4px;
}

@media (min-width: 720px) {
	/* let's not enforce col widths except above 720px */
	.file-information th {
		width: 15%;
	}
}

/* Dark mode fixes */
html.skin-theme-clientpref-night .file-information th {
	background: #2a2a5c;
	color: white;
}

@media screen and (prefers-color-scheme: dark) {
	html.skin-theme-clientpref-os .file-information th {
		background: #2a2a5c;
		color: white;
	}
}

